#include<bits/stdc++.h>
#include <cstring>
#include <iostream>

using namespace std;

// pornesc o parcurgere DFS din node
// folosesc vectorul used pentru a marca nodurile vizitate
void dfs(int node, vector<int>& used, vector<int>& topsort,
            vector<set<int>> &muchii) {
    used[node] = 1;  // marchez nodul ca fiind vizitat

    // ii parcurg vecinii din set
    set<int> neigh_node = muchii[node];
    set<int>:: iterator it;
    for (it =neigh_node.begin(); it!= neigh_node.end(); ++it) {
        int next_node = *it;
        if (!used[next_node]) {
            dfs(next_node, used, topsort, muchii);
        }
    }

    // dupa ce am vizitat recursiv toti vecinii, adaug nodul in vector
    topsort.push_back(node);
}

vector<int> solve_dfs(vector<set<int>> &muchii, int m) {
    //  vectorul rezultat (in final contine o permutare pentru 1, 2, ..., n)
    vector<int> topsort;

    // used[node] = 1 daca node a fost deja vizitat, 0 altfel
    vector<int> used(m + 1, 0);

    // iau fiecare nod
    for (int node = 1; node <= m; ++node) {
        //  daca nodul este nevizitat, pornesc o parcurgere
        if (!used[node]) {
            dfs(node, used, topsort, muchii);
        }
    }

    // rezultatul a fost obtinut in ordine inversa
    reverse(topsort.begin(), topsort.end());
    return topsort;
}

int main(void) {
    ifstream fin;
    ofstream fout;
    int n, m, a, num;
    fin.open("curse.in");
    fout.open("curse.out");
    fin >> n >> m >> a;
    vector<vector<int>> matrix(a);
    // complexitate temporala O(a * n)
    for (int i = 0; i < a; i++) {
        for (int j = 0; j < n; j++) {
            fin >> num;
            matrix[i].push_back(num);
        }
    }

    vector<set<int>> muchii(m + 1);

    // compar elementele de pe cate 2 linii,
    // atunci cand gasesc pe o coloana doua elemente diferite
    // adaug elementul de pe a doua linie in lista de vecini a primului element
    // si trec la urmatoarea linie
    // complexitate temporala O(a * n)
    for (int i = 0; i < a - 1; i++) {
        for (int j = 0; j < n; j++) {
            if (matrix[i][j] != matrix[i + 1][j]) {
                muchii[matrix[i][j]].insert(matrix[i + 1][j]);
                break;
            }
        }
    }
    // Complexitate temporala O(m + a)
    vector<int> toposort = solve_dfs(muchii, m);

    // complexitate temporala O(n)
    for (int i = 0; i < toposort.size(); i++) {
        fout << toposort[i]<< " ";
    }
    fout<< endl;
    fout.close();
    fin.close();
}

import java.io.BufferedReader;
import java.io.File;
import java.io.FileNotFoundException;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;

import java.util.ArrayList;
import java.util.Iterator; 
import java.util.LinkedList;
import java.util.Queue;
import java.util.Stack;


class Curse {

	static class Graph {

		private int V;
		private ArrayList<ArrayList<Integer>> adj;

		Graph(int v) {
			V = v;
			adj = new ArrayList<ArrayList<Integer>>(v);
			for (int i = 0; i < v; ++i) {
				adj.add(new ArrayList<Integer>());
			}
		}

		void addEdge(int v, int w) { 
			adj.get(v).add(w); 
		}

		void topologicalSortUtil(int v, boolean[] visited, Stack<Integer> stack) {

			visited[v] = true;
			Integer i;

			Iterator<Integer> it = adj.get(v).iterator();
			while (it.hasNext()) {
				i = it.next();
				if (!visited[i]) {
					topologicalSortUtil(i, visited, stack);
				}
			}

			Integer nr = v;
			stack.push(nr);
		}

		void topologicalSort(PrintWriter printWriter) {

			Stack<Integer> stack = new Stack<Integer>();
			boolean[] visited = new boolean[V];
			for (int i = 0; i < V; i++) {
				visited[i] = false;
			}

			for (int i = 0; i < V; i++) {
				if (visited[i] == false) {
					topologicalSortUtil(i, visited, stack);
				}
			}

			while (stack.empty() == false) {
				int nr = (stack.pop() + 1);
				printWriter.print(nr + " ");
			}
		}
	}

	public static void main(String[] args) throws FileNotFoundException, IOException {

		BufferedReader reader = new BufferedReader(new FileReader("curse.in"));
		String line = reader.readLine();
		String[] first_line = line.split(" ");
		int N = Integer.parseInt(first_line[0]);
		int M = Integer.parseInt(first_line[1]);
		final int A = Integer.parseInt(first_line[2]);
		ArrayList<Integer> store = new ArrayList<>(20);
		Graph g = new Graph(M);

		line = reader.readLine();
		first_line = line.split(" ");

		for (int i = 0;i < N; i++) {
			store.add(Integer.parseInt(first_line[i]));
		}

		for (int i = 1;i < A;i++) {

			line = reader.readLine();
			first_line = line.split(" ");
			for (int j = 0;j < N;j++) {
				if (store.get(j) == Integer.parseInt(first_line[j])) {
					continue;
				} else {

					int node1 = store.get(j);
					int node2 = Integer.parseInt(first_line[j]);
					g.addEdge(node1 - 1, node2 - 1);
					store = new ArrayList<>(20);
					for (String text : first_line) {
						store.add(Integer.parseInt(text));
					}
					break;

				}
			}
		}

		FileWriter fileWriter = new FileWriter("curse.out");
		PrintWriter printWriter = new PrintWriter(fileWriter);

		g.topologicalSort(printWriter);

		printWriter.close();
	}
}
